#include "./main.h"
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#ifdef TIMING
#include <sys/time.h>
#endif

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	fp* image,											
							int Nr,												
							int Nc,												
							long Ne,											
							int niter,											
							fp lambda,											
							long NeROI,											
							int* iN,
							int* iS,
							int* jW,
							int* jE,
							int iter,											
							int mem_size_i,
							int mem_size_j)
{

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
                d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    int blocks_x;
    int mem_size = sizeof(fp) * Ne;

    fp* d_I = (fp*)malloc(mem_size);
    fp* d_iN = (fp*)malloc(mem_size_i); // Note: Original code allocates int buffer here, but type is fp* in declaration. Keeping logic consistent with usage.
    // Actually, iN, iS are int*, d_iN etc in OpenCL are cl_mem. 
    // In OpenMP, we just use the host arrays directly or copy them. 
    // The wrapper receives int* iN, iS, jE, jW. We can use them directly.
    // The OpenCL code copies them to device buffers. In OpenMP, we just use the pointers.

    // Re-declaring pointers to match the logic of "device" memory in OpenMP context (which is just host memory)
    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);
    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);
    fp* d_c = (fp*)malloc(mem_size);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy input image to "device" memory (d_I)
    memcpy(d_I, image, mem_size);

    // iN, iS, jW, jE are already in host memory and passed in, no copy needed for OpenMP

#ifdef TIMING
    h2d_time = 0; // Simplified timing for OpenMP
#endif

    int local_work_size = NUMBER_THREADS;
    int blocks_work_size = Ne / local_work_size;
    if (Ne % local_work_size != 0) {
        blocks_work_size++;
    }
    long global_work_size = (long)blocks_work_size * local_work_size;

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", blocks_work_size, local_work_size);

    // Extract Kernel
    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ++ei) {
        d_I[ei] = exp(d_I[ei]/255.0f);
    }

#ifdef TIMING
    kernel_time += 0; // Timing placeholder
#endif

    // Prepare variables for reduction loop
    long no;
    int mul;
    int mem_size_single = sizeof(fp) * 1;
    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    printf("Iterations Progress: hidden");

    for (iter=0; iter<niter; iter++){
        fflush(NULL);

        // Prepare Kernel
        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            d_sums[ei] = d_I[ei];
            d_sums2[ei] = d_I[ei]*d_I[ei];
        }

        // Reduction Loop
        int blocks2_work_size = blocks_work_size;
        no = Ne;
        mul = 1;

        while(blocks2_work_size != 0){
            // Reduce Kernel Simulation
            // Since OpenMP doesn't have the exact same block/thread structure as OpenCL/CUDA,
            // we implement the reduction logic using a parallel approach that mimics the behavior
            // or simply performs the reduction efficiently.
            // The original code does a tree reduction in blocks. 
            // Here we will perform the reduction step for the current level.

            long current_no = no;
            long next_no = blocks2_work_size;
            int current_mul = mul;

            // We need to simulate the block-based reduction. 
            // In OpenMP, we can parallelize the blocks.
            // Each "block" in the original code processes NUMBER_THREADS elements.

            #pragma omp parallel
            {
                int tx = omp_get_thread_num();
                int num_threads = omp_get_num_threads();

                // Ensure we don't exceed intended block size logic if possible, 
                // but for correctness of the algorithm, we must follow the block structure.
                // The original code assumes NUMBER_THREADS per block.
                // We will force the number of threads to match blocks2_work_size * NUMBER_THREADS?
                // No, that's inefficient. 
                // Let's restructure: The reduction kernel processes 'blocks2_work_size' blocks.
                // Each block reduces NUMBER_THREADS elements into 1.

                // To strictly follow the algorithm without rewriting the reduction logic entirely:
                // We iterate over blocks.

                #pragma omp for
                for (int bx = 0; bx < blocks2_work_size; ++bx) {
                    fp local_psum[NUMBER_THREADS];
                    fp local_psum2[NUMBER_THREADS];

                    int nf = NUMBER_THREADS - (blocks2_work_size * NUMBER_THREADS - current_no);
                    int df = 0;

                    // Load data
                    for (int t = 0; t < NUMBER_THREADS; ++t) {
                        long ei = bx * NUMBER_THREADS + t;
                        if (ei < current_no) {
                            local_psum[t] = d_sums[ei * current_mul];
                            local_psum2[t] = d_sums2[ei * current_mul];
                        } else {
                            local_psum[t] = 0.0f;
                            local_psum2[t] = 0.0f;
                        }
                    }

                    // Barrier equivalent (implicit in single thread execution of block, but we are in parallel for)
                    // Since each block is handled by one thread in this loop, no sync needed within thread.

                    if (nf == NUMBER_THREADS) {
                        for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                            if ((tx + 1) % i == 0) {
                                local_psum[tx] += local_psum[tx - i/2];
                                local_psum2[tx] += local_psum2[tx - i/2];
                            }
                        }
                        if (tx == NUMBER_THREADS - 1) {
                            d_sums[bx * current_mul * NUMBER_THREADS] = local_psum[tx];
                            d_sums2[bx * current_mul * NUMBER_THREADS] = local_psum2[tx];
                        }
                    } else {
                        if (bx != (blocks2_work_size - 1)) {
                            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                                if ((tx + 1) % i == 0) {
                                    local_psum[tx] += local_psum[tx - i/2];
                                    local_psum2[tx] += local_psum2[tx - i/2];
                                }
                            }
                            if (tx == NUMBER_THREADS - 1) {
                                d_sums[bx * current_mul * NUMBER_THREADS] = local_psum[tx];
                                d_sums2[bx * current_mul * NUMBER_THREADS] = local_psum2[tx];
                            }
                        } else {
                            // Last block with partial data
                            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                                if (nf >= i) {
                                    df = i;
                                }
                            }

                            for (int i = 2; i <= df; i = 2 * i) {
                                if ((tx + 1) % i == 0 && tx < df) {
                                    local_psum[tx] += local_psum[tx - i/2];
                                    local_psum2[tx] += local_psum2[tx - i/2];
                                }
                            }

                            if (tx == df - 1) {
                                for (long i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                                    local_psum[tx] += d_sums[i];
                                    local_psum2[tx] += d_sums2[i];
                                }
                                d_sums[bx * current_mul * NUMBER_THREADS] = local_psum[tx];
                                d_sums2[bx * current_mul * NUMBER_THREADS] = local_psum2[tx];
                            }
                        }
                    }
                }
            }

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / local_work_size;
                if (blocks2_work_size % local_work_size != 0) {
                    blocks_x++;
                }
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        // SRAD Kernel
        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            int row = (ei + 1) % Nr - 1;
            int col = (ei + 1) / Nr + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_Jc = d_I[ei];
            fp d_dN_loc = d_I[iN[row] + Nr * col] - d_Jc;
            fp d_dS_loc = d_I[iS[row] + Nr * col] - d_Jc;
            fp d_dW_loc = d_I[row + Nr * jW[col]] - d_Jc;
            fp d_dE_loc = d_I[row + Nr * jE[col]] - d_Jc;

            fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
            fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
            fp d_den = 1.0f + (0.25f * d_L);
            fp d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            fp d_c_loc = 1.0f / (1.0f + d_den);

            if (d_c_loc < 0.0f) d_c_loc = 0.0f;
            else if (d_c_loc > 1.0f) d_c_loc = 1.0f;

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }

        // SRAD2 Kernel
        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ++ei) {
            int row = (ei + 1) % Nr - 1;
            int col = (ei + 1) / Nr + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_cN = d_c[ei];
            fp d_cS = d_c[iS[row] + Nr * col];
            fp d_cW = d_c[ei];
            fp d_cE = d_c[row + Nr * jE[col]];

            fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + 0.25f * lambda * d_D;
        }
    }

    printf("\n");

    // Compress Kernel
    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ++ei) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }

    // Copy result back to image
    memcpy(image, d_I, mem_size);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    free(d_I);
    free(d_sums);
    free(d_sums2);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
